package main.rice;

import java.util.ArrayList;
import java.util.List;

/**
 * This class implements a relatively simple algorithm for computing (and printing) the
 * prime factors of a number.  At initialization, a list of primes is computed. Given a
 * number, this list is used to efficiently compute the prime factors of that number.
 */
public class PrimeFactorizer {

    private List<Integer> primes;
    private int maxNumToFactorize;

    public PrimeFactorizer(int maxNumToFactorize) {
        this.maxNumToFactorize = maxNumToFactorize;
        this.primes = sieveOfEratosthenes(maxNumToFactorize);
    }

    /**
     * Computes the prime factorization of the given number.
     * Returns an array of prime factors in ascending order, including repeats.
     * Returns null for invalid inputs (negative, 0, 1, or exceeding maxNumToFactorize).
     */
    public int[] computePrimeFactorization(int numToFactorize) {
        // Edge cases: negative, 0, or 1 should return null
        if (numToFactorize <= 1) {
            return null;
        }

        // Numbers exceeding maxNumToFactorize should return null
        if (numToFactorize > maxNumToFactorize) {
            return null;
        }

        List<Integer> factors = new ArrayList<>();
        int remaining = numToFactorize;

        // Try each prime in the precomputed list
        for (int prime : primes) {
            // If prime squared is greater than remaining, any remaining value is prime itself
            if (prime * prime > remaining) {
                break;
            }

            // Divide out this prime as many times as possible
            while (remaining % prime == 0) {
                factors.add(prime);
                remaining /= prime;
            }
        }

        // If remaining > 1, it is a prime factor
        if (remaining > 1) {
            factors.add(remaining);
        }

        // Convert list to array
        int[] result = new int[factors.size()];
        for (int i = 0; i < factors.size(); i++) {
            result[i] = factors.get(i);
        }

        return result;
    }

    /**
     * Generates all prime numbers up to n using the Sieve of Eratosthenes algorithm.
     */
    private List<Integer> sieveOfEratosthenes(int n) {
        List<Integer> primes = new ArrayList<>();

        if (n < 2) {
            return primes;
        }

        boolean[] isPrime = new boolean[n + 1];
        for (int i = 2; i <= n; i++) {
            isPrime[i] = true;
        }

        for (int i = 2; i * i <= n; i++) {
            if (isPrime[i]) {
                for (int j = i * i; j <= n; j += i) {
                    isPrime[j] = false;
                }
            }
        }

        for (int i = 2; i <= n; i++) {
            if (isPrime[i]) {
                primes.add(i);
            }
        }

        return primes;
    }
}

