package test.rice;

import main.rice.PrimeFactorizer;
import org.junit.jupiter.api.Test;

import static org.junit.jupiter.api.Assertions.assertArrayEquals;
import static org.junit.jupiter.api.Assertions.assertNull;

/**
 * Comprehensive agent tests for the PrimeFactorizer class.
 */
public class PrimeFactorizerAgentTest {

    private static final PrimeFactorizer smallFactorizer = new PrimeFactorizer(100);
    private static final PrimeFactorizer largeFactorizer = new PrimeFactorizer(50000000);

    // ==================== Edge Cases ====================

    @Test
    void testFactorize1() {
        // 1 is neither prime nor composite, should return null
        int[] actual = smallFactorizer.computePrimeFactorization(1);
        assertNull(actual);
    }

    @Test
    void testFactorizeNegative() {
        int[] actual = smallFactorizer.computePrimeFactorization(-5);
        assertNull(actual);
    }

    @Test
    void testFactorize0() {
        int[] actual = smallFactorizer.computePrimeFactorization(0);
        assertNull(actual);
    }

    @Test
    void testFactorizeExceedsMax() {
        // 101 > 100, should return null
        int[] actual = smallFactorizer.computePrimeFactorization(101);
        assertNull(actual);
    }

    @Test
    void testFactorizeExceedsMax2() {
        // 1000 > 100, should return null
        int[] actual = smallFactorizer.computePrimeFactorization(1000);
        assertNull(actual);
    }

    // ==================== Prime Numbers ====================

    @Test
    void testFactorize2() {
        // 2 is prime
        int[] actual = smallFactorizer.computePrimeFactorization(2);
        int[] expected = {2};
        assertArrayEquals(expected, actual);
    }

    @Test
    void testFactorize3() {
        // 3 is prime
        int[] actual = smallFactorizer.computePrimeFactorization(3);
        int[] expected = {3};
        assertArrayEquals(expected, actual);
    }

    @Test
    void testFactorize5() {
        // 5 is prime
        int[] actual = smallFactorizer.computePrimeFactorization(5);
        int[] expected = {5};
        assertArrayEquals(expected, actual);
    }

    @Test
    void testFactorize7() {
        // 7 is prime
        int[] actual = smallFactorizer.computePrimeFactorization(7);
        int[] expected = {7};
        assertArrayEquals(expected, actual);
    }

    @Test
    void testFactorize97() {
        // 97 is prime
        int[] actual = smallFactorizer.computePrimeFactorization(97);
        int[] expected = {97};
        assertArrayEquals(expected, actual);
    }

    // ==================== Composite Numbers (Powers of 2) ====================

    @Test
    void testFactorize4() {
        // 4 = 2 * 2
        int[] actual = smallFactorizer.computePrimeFactorization(4);
        int[] expected = {2, 2};
        assertArrayEquals(expected, actual);
    }

    @Test
    void testFactorize8() {
        // 8 = 2 * 2 * 2
        int[] actual = smallFactorizer.computePrimeFactorization(8);
        int[] expected = {2, 2, 2};
        assertArrayEquals(expected, actual);
    }

    @Test
    void testFactorize16() {
        // 16 = 2 * 2 * 2 * 2
        int[] actual = smallFactorizer.computePrimeFactorization(16);
        int[] expected = {2, 2, 2, 2};
        assertArrayEquals(expected, actual);
    }

    // ==================== Composite Numbers (Mixed Factors) ====================

    @Test
    void testFactorize6() {
        // 6 = 2 * 3
        int[] actual = smallFactorizer.computePrimeFactorization(6);
        int[] expected = {2, 3};
        assertArrayEquals(expected, actual);
    }

    @Test
    void testFactorize12() {
        // 12 = 2 * 2 * 3
        int[] actual = smallFactorizer.computePrimeFactorization(12);
        int[] expected = {2, 2, 3};
        assertArrayEquals(expected, actual);
    }

    @Test
    void testFactorize30() {
        // 30 = 2 * 3 * 5
        int[] actual = smallFactorizer.computePrimeFactorization(30);
        int[] expected = {2, 3, 5};
        assertArrayEquals(expected, actual);
    }

    @Test
    void testFactorize60() {
        // 60 = 2 * 2 * 3 * 5
        int[] actual = smallFactorizer.computePrimeFactorization(60);
        int[] expected = {2, 2, 3, 5};
        assertArrayEquals(expected, actual);
    }

    @Test
    void testFactorize100() {
        // 100 = 2 * 2 * 5 * 5
        int[] actual = smallFactorizer.computePrimeFactorization(100);
        int[] expected = {2, 2, 5, 5};
        assertArrayEquals(expected, actual);
    }

    // ==================== Large Numbers ====================

    @Test
    void testFactorizeLarge() {
        // Test with large factorizer
        int[] actual = largeFactorizer.computePrimeFactorization(1000000);
        // 1000000 = 2^6 * 5^6 = 2 * 2 * 2 * 2 * 2 * 2 * 5 * 5 * 5 * 5 * 5 * 5
        int[] expected = {2, 2, 2, 2, 2, 2, 5, 5, 5, 5, 5, 5};
        assertArrayEquals(expected, actual);
    }

    @Test
    void testFactorize12345() {
        // 12345 = 3 * 5 * 823
        int[] actual = largeFactorizer.computePrimeFactorization(12345);
        int[] expected = {3, 5, 823};
        assertArrayEquals(expected, actual);
    }

    // ==================== More Edge Cases ====================

    @Test
    void testFactorize15() {
        // 15 = 3 * 5
        int[] actual = smallFactorizer.computePrimeFactorization(15);
        int[] expected = {3, 5};
        assertArrayEquals(expected, actual);
    }

    @Test
    void testFactorize25() {
        // 25 = 5 * 5
        int[] actual = smallFactorizer.computePrimeFactorization(25);
        int[] expected = {5, 5};
        assertArrayEquals(expected, actual);
    }

    @Test
    void testFactorize49() {
        // 49 = 7 * 7
        int[] actual = smallFactorizer.computePrimeFactorization(49);
        int[] expected = {7, 7};
        assertArrayEquals(expected, actual);
    }

    @Test
    void testFactorize72() {
        // 72 = 2 * 2 * 2 * 3 * 3
        int[] actual = smallFactorizer.computePrimeFactorization(72);
        int[] expected = {2, 2, 2, 3, 3};
        assertArrayEquals(expected, actual);
    }

    @Test
    void testFactorize90() {
        // 90 = 2 * 3 * 3 * 5
        int[] actual = smallFactorizer.computePrimeFactorization(90);
        int[] expected = {2, 3, 3, 5};
        assertArrayEquals(expected, actual);
    }

    @Test
    void testFactorizeLargeAtMax() {
        // Test at the boundary of large factorizer's max
        int[] actual = largeFactorizer.computePrimeFactorization(49999999);
        // This should factorize correctly regardless of what the factors are
        assertArrayEquals(factorizeNaive(49999999), actual);
    }

    // Helper method to verify factorization
    private int[] factorizeNaive(int n) {
        java.util.List<Integer> factors = new java.util.ArrayList<>();
        int remaining = n;

        for (int i = 2; i * i <= remaining; i++) {
            while (remaining % i == 0) {
                factors.add(i);
                remaining /= i;
            }
        }

        if (remaining > 1) {
            factors.add(remaining);
        }

        int[] result = new int[factors.size()];
        for (int i = 0; i < factors.size(); i++) {
            result[i] = factors.get(i);
        }
        return result;
    }
}
